import "./navigation-menu.css";

import { NavigationMenu } from "radix-ui";
import { cn } from "tailwind-variants";

import { NavigationMenuContext, useNavigationMenuContext } from "./navigation-menu.context";
import { navigationMenuVariants } from "./navigation-menu.variants";

export type NavigationMenuRootProps = React.ComponentProps<typeof NavigationMenu.Root>;

export const NavigationMenuRoot = ({ children, className, ...props }: NavigationMenuRootProps) => {
  const slots = navigationMenuVariants();

  return (
    <NavigationMenuContext value={{ slots }}>
      <NavigationMenu.Root className={cn(slots.root(), className)} {...props}>
        {children}
        <NavigationMenuViewport />
      </NavigationMenu.Root>
    </NavigationMenuContext>
  );
};

const NavigationMenuViewport = () => {
  const { slots } = useNavigationMenuContext();

  return (
    <div className={slots.viewportWrapper()}>
      <NavigationMenu.Viewport className={slots.viewport()} />
    </div>
  );
};

import { NavigationMenu } from "radix-ui";
import { cn } from "tailwind-variants";

import { useNavigationMenuContext } from "./navigation-menu.context";

export type NavigationMenuListProps = React.ComponentProps<typeof NavigationMenu.List>;

export const NavigationMenuList = ({ className, ...props }: NavigationMenuListProps) => {
  const { slots } = useNavigationMenuContext();

  return <NavigationMenu.List className={cn(slots.list(), className)} {...props} />;
};

import { NavigationMenu } from "radix-ui";

export type NavigationMenuItemProps = React.ComponentProps<typeof NavigationMenu.Item>;

export const NavigationMenuItem = (props: NavigationMenuItemProps) => {
  return <NavigationMenu.Item {...props} />;
};

import { ChevronDown } from "lucide-react";
import { NavigationMenu } from "radix-ui";
import { cn } from "tailwind-variants";

import { useNavigationMenuContext } from "./navigation-menu.context";

export type NavigationMenuTriggerProps = React.ComponentProps<typeof NavigationMenu.Trigger>;

export const NavigationMenuTrigger = ({
  children,
  className,
  ...props
}: NavigationMenuTriggerProps) => {
  const { slots } = useNavigationMenuContext();

  return (
    <NavigationMenu.Trigger className={cn(slots.trigger(), className)} {...props}>
      {children}
      <ChevronDown aria-hidden className="navigation-menu__chevron" />
    </NavigationMenu.Trigger>
  );
};

import { NavigationMenu } from "radix-ui";
import { cn } from "tailwind-variants";

import { useNavigationMenuContext } from "./navigation-menu.context";

export type NavigationMenuContentProps = React.ComponentProps<typeof NavigationMenu.Content>;

export const NavigationMenuContent = ({ className, ...props }: NavigationMenuContentProps) => {
  const { slots } = useNavigationMenuContext();

  return <NavigationMenu.Content className={cn(slots.content(), className)} {...props} />;
};

import { NavigationMenu } from "radix-ui";
import { cn } from "tailwind-variants";

import { useNavigationMenuContext } from "./navigation-menu.context";

export type NavigationMenuLinkProps = React.ComponentProps<typeof NavigationMenu.Link>;

export const NavigationMenuLink = ({ className, ...props }: NavigationMenuLinkProps) => {
  const { slots } = useNavigationMenuContext();

  return <NavigationMenu.Link className={cn(slots.link(), className)} {...props} />;
};

import { createContext, useContext } from "react";

import { navigationMenuVariants } from "./navigation-menu.variants";

export type NavigationMenuContext = {
  slots: ReturnType<typeof navigationMenuVariants>;
};

export const NavigationMenuContext = createContext<NavigationMenuContext | null>(null);

export const useNavigationMenuContext = () => {
  const context = useContext(NavigationMenuContext);
  if (!context) {
    throw new Error("useNavigationMenuContext must be used within a NavigationMenu");
  }
  return context;
};

import { tv, type VariantProps } from "tailwind-variants";

export const navigationMenuVariants = tv({
  slots: {
    content: "navigation-menu__content",
    indicator: "navigation-menu__indicator",
    link: "navigation-menu__link",
    list: "navigation-menu__list",
    root: "navigation-menu",
    trigger: "navigation-menu__trigger",
    viewport: "navigation-menu__viewport",
    viewportWrapper: "navigation-menu__viewport-wrapper",
  },
});

export type NavigationMenuVariants = VariantProps<typeof navigationMenuVariants>;

.navigation-menu {
  @apply relative z-10 flex max-w-max flex-1 items-center justify-center;
}

.navigation-menu__list {
  @apply flex flex-1 list-none items-center justify-center gap-1;
}

.navigation-menu__trigger {
  @apply bg-background inline-flex h-9 w-max items-center justify-center rounded-md px-4 py-2 text-sm font-medium transition-colors;

  &:hover {
    @apply bg-accent text-accent-foreground;
  }

  &:focus-visible {
    @apply outline-ring outline-2 outline-offset-2;
  }

  &[data-state="open"] > .navigation-menu__chevron {
    @apply rotate-180;
  }
}

.navigation-menu__chevron {
  @apply relative top-px ml-1 size-3 transition-transform duration-200;
}

.navigation-menu__content {
  @apply top-0 left-0 w-full md:absolute md:w-auto;

  &[data-motion="from-start"] {
    @apply animate-in fade-in slide-in-from-left-52;
  }

  &[data-motion="from-end"] {
    @apply animate-in fade-in slide-in-from-right-52;
  }

  &[data-motion="to-start"] {
    @apply animate-out fade-out slide-out-to-left-52;
  }

  &[data-motion="to-end"] {
    @apply animate-out fade-out slide-out-to-right-52;
  }
}

.navigation-menu__link {
  @apply block rounded-md p-3 text-sm leading-none no-underline transition-colors outline-none select-none;

  &:hover {
    @apply bg-accent text-accent-foreground;
  }

  &:focus-visible {
    @apply outline-ring outline-2 outline-offset-2;
  }
}

.navigation-menu__indicator {
  @apply top-full z-10 flex h-1.5 items-end justify-center overflow-hidden;

  &[data-state="visible"] {
    @apply animate-in fade-in;
  }

  &[data-state="hidden"] {
    @apply animate-out fade-out;
  }
}

.navigation-menu__viewport-wrapper {
  @apply absolute top-full left-0 flex justify-center;
}

.navigation-menu__viewport {
  @apply bg-popover text-popover-foreground relative mt-1.5 h-[var(--radix-navigation-menu-viewport-height)] w-full origin-[top_center] overflow-hidden rounded-md border shadow-md md:w-[var(--radix-navigation-menu-viewport-width)];

  &[data-state="open"] {
    @apply animate-in fade-in zoom-in-90;
  }

  &[data-state="closed"] {
    @apply animate-out fade-out zoom-out-95;
  }
}

import { NavigationMenuContent } from "./navigation-menu-content";
import { NavigationMenuItem } from "./navigation-menu-item";
import { NavigationMenuLink } from "./navigation-menu-link";
import { NavigationMenuList } from "./navigation-menu-list";
import { NavigationMenuRoot } from "./navigation-menu-root";
import { NavigationMenuTrigger } from "./navigation-menu-trigger";

export const NavigationMenu = {
  Content: NavigationMenuContent,
  Item: NavigationMenuItem,
  Link: NavigationMenuLink,
  List: NavigationMenuList,
  Root: NavigationMenuRoot,
  Trigger: NavigationMenuTrigger,
};

export {
  NavigationMenuContent,
  NavigationMenuItem,
  NavigationMenuLink,
  NavigationMenuList,
  NavigationMenuRoot,
  NavigationMenuTrigger,
};

export type { NavigationMenuContentProps } from "./navigation-menu-content";

export type { NavigationMenuItemProps } from "./navigation-menu-item";

export type { NavigationMenuLinkProps } from "./navigation-menu-link";
export type { NavigationMenuListProps } from "./navigation-menu-list";
export type { NavigationMenuRootProps } from "./navigation-menu-root";
export type { NavigationMenuTriggerProps } from "./navigation-menu-trigger";
export { NavigationMenuContext, useNavigationMenuContext } from "./navigation-menu.context";
export { type NavigationMenuVariants, navigationMenuVariants } from "./navigation-menu.variants";
